#include<bits/stdc++.h>
using namespace std;
struct mm{int a,b;}l[2000000];
bool cmp(mm x,mm y){return x.b<y.b;}
int main(void){
    int n,ans=1,m;
	std::scanf("%d",&n);
    for(int i=1;i<=n;i++)cin>>l[i].a>>l[i].b;
    std::sort(l+1,l+n+1,cmp);m=l[1].b;
    int j=1;while(j<=n){j++;if(l[j].a>=m)ans++,m=l[j].b;}
    std::printf("%d",ans);
    return false;
}
